@app.route('/documents', methods=['POST'])
def create_document():
    data = request.get_json()
    
    required_fields = ['title', 'content', 'author_id']
    if not all(field in data for field in required_fields):
        return jsonify({'error': 'Missing required fields'}), 400
    
    try:
        author = users_collection.find_one({'_id': ObjectId(data['author_id'])})
        if not author:
            return jsonify({'error': 'Author not found'}), 404
        
        document = {
            'title': data['title'],
            'content': data['content'],
            'author_id': ObjectId(data['author_id']),
            'author_name': author['full_name'],
            'status': data.get('status', 'draft'),
            'tags': data.get('tags', []),
            'category': data.get('category', ''),
            'views': 0,
            'likes': 0,
            'created_at': datetime.utcnow(),
            'updated_at': datetime.utcnow(),
            'published_at': None,
            'metadata': data.get('metadata', {})
        }
        
        if document['status'] == 'published':
            document['published_at'] = datetime.utcnow()
        
        result = documents_collection.insert_one(document)
        document['_id'] = str(result.inserted_id)
        
        return jsonify({'message': 'Document created successfully', 'document': serialize_doc(document)}), 201
    except Exception as e:
        return jsonify({'error': str(e)}), 400


@app.route('/documents/<document_id>', methods=['GET'])
def get_document(document_id):
    try:
        document = documents_collection.find_one({'_id': ObjectId(document_id)})
        if document:
            documents_collection.update_one(
                {'_id': ObjectId(document_id)},
                {'$inc': {'views': 1}}
            )
            document['views'] += 1
            return jsonify({'document': serialize_doc(document)}), 200
        return jsonify({'error': 'Document not found'}), 404
    except Exception as e:
        return jsonify({'error': str(e)}), 400


@app.route('/documents/<document_id>', methods=['PUT'])
def update_document(document_id):
    data = request.get_json()
    
    try:
        update_data = {
            'updated_at': datetime.utcnow()
        }
        
        allowed_fields = ['title', 'content', 'status', 'tags', 'category', 'metadata']
        for field in allowed_fields:
            if field in data:
                update_data[field] = data[field]
        
        if 'status' in data and data['status'] == 'published':
            existing_doc = documents_collection.find_one({'_id': ObjectId(document_id)})
            if existing_doc and existing_doc.get('status') != 'published':
                update_data['published_at'] = datetime.utcnow()
        
        result = documents_collection.update_one(
            {'_id': ObjectId(document_id)},
            {'$set': update_data}
        )
        
        if result.matched_count:
            document = documents_collection.find_one({'_id': ObjectId(document_id)})
            return jsonify({'message': 'Document updated successfully', 'document': serialize_doc(document)}), 200
        return jsonify({'error': 'Document not found'}), 404
    except Exception as e:
        return jsonify({'error': str(e)}), 400


