@app.route('/documents', methods=['GET'])
def query_documents():
    try:
        page = int(request.args.get('page', 1))
        limit = int(request.args.get('limit', 10))
        skip = (page - 1) * limit
        
        query = {}
        
        if request.args.get('author_id'):
            query['author_id'] = ObjectId(request.args.get('author_id'))
        
        if request.args.get('status'):
            query['status'] = request.args.get('status')
        
        if request.args.get('category'):
            query['category'] = request.args.get('category')
        
        if request.args.get('tag'):
            query['tags'] = request.args.get('tag')
        
        if request.args.get('search'):
            search_term = request.args.get('search')
            query['$or'] = [
                {'title': {'$regex': search_term, '$options': 'i'}},
                {'content': {'$regex': search_term, '$options': 'i'}}
            ]
        
        sort_by = request.args.get('sort_by', 'created_at')
        sort_order = DESCENDING if request.args.get('sort_order', 'desc') == 'desc' else ASCENDING
        
        documents = list(documents_collection.find(query).sort(sort_by, sort_order).skip(skip).limit(limit))
        total = documents_collection.count_documents(query)
        
        return jsonify({
            'documents': [serialize_doc(doc) for doc in documents],
            'total': total,
            'page': page,
            'limit': limit
        }), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 400


