@app.route('/analytics/engagement', methods=['GET'])
def engagement_metrics():
    try:
        author_id = request.args.get('author_id')
        
        match_stage = {}
        if author_id:
            match_stage = {'$match': {'author_id': ObjectId(author_id)}}
        
        pipeline = []
        if match_stage:
            pipeline.append(match_stage)
        
        pipeline.extend([
            {
                '$facet': {
                    'overall_stats': [
                        {
                            '$group': {
                                '_id': None,
                                'total_documents': {'$sum': 1},
                                'total_views': {'$sum': '$views'},
                                'total_likes': {'$sum': '$likes'},
                                'avg_views_per_doc': {'$avg': '$views'},
                                'avg_likes_per_doc': {'$avg': '$likes'},
                                'max_views': {'$max': '$views'},
                                'max_likes': {'$max': '$likes'}
                            }
                        }
                    ],
                    'top_documents': [
                        {
                            '$sort': {'views': -1}
                        },
                        {
                            '$limit': 5
                        },
                        {
                            '$project': {
                                'title': 1,
                                'views': 1,
                                'likes': 1,
                                'created_at': 1
                            }
                        }
                    ],
                    'status_breakdown': [
                        {
                            '$group': {
                                '_id': '$status',
                                'count': {'$sum': 1}
                            }
                        }
                    ]
                }
            }
        ])
        
        results = list(documents_collection.aggregate(pipeline))
        
        return jsonify({'engagement_metrics': serialize_doc(results[0] if results else {})}), 200
    except Exception as e:
        return jsonify({'error': str(e)}), 400


def serialize_doc(doc):
    if isinstance(doc, list):
        return [serialize_doc(item) for item in doc]
    if isinstance(doc, dict):
        serialized = {}
        for key, value in doc.items():
            if isinstance(value, ObjectId):
                serialized[key] = str(value)
            elif isinstance(value, datetime):
                serialized[key] = value.isoformat()
            elif isinstance(value, dict):
                serialized[key] = serialize_doc(value)
            elif isinstance(value, list):
                serialized[key] = serialize_doc(value)
            else:
                serialized[key] = value
        return serialized
    return doc


